"Risk Variable Encounter with Osteoporosis Present on Admission" AS (
SELECT * FROM "Qualifying Encounter" AS InpatientEncounter WHERE EXISTS (SELECT 1 FROM (SELECT unnest(from_json(fhirpath((SELECT COALESCE('[' || string_agg(Claims.resource, ',') || ']', '[]') FROM "Claim" AS Claims WHERE fhirpath_text(Claims.resource, 'status') = 'active' AND fhirpath_text(Claims.resource, 'use') = 'claim' AND fhirpath_text(InpatientEncounter.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(Claims.resource, 'item.encounter.reference'), '/'), -1)), 'diagnosis'), '["VARCHAR"]')) AS _lt_ClaimsDiag) AS _lt_unnest WHERE list_contains(from_json(fhirpath(CASE WHEN fhirpath_text(InpatientEncounter.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text((SELECT COALESCE('[' || string_agg(Claims.resource, ',') || ']', '[]') FROM "Claim" AS Claims WHERE fhirpath_text(Claims.resource, 'status') = 'active' AND fhirpath_text(Claims.resource, 'use') = 'claim' AND fhirpath_text(InpatientEncounter.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(Claims.resource, 'item.encounter.reference'), '/'), -1)), 'item.encounter.reference'), '/'), -1) THEN fhirpath_text((SELECT COALESCE('[' || string_agg(Claims.resource, ',') || ']', '[]') FROM "Claim" AS Claims WHERE fhirpath_text(Claims.resource, 'status') = 'active' AND fhirpath_text(Claims.resource, 'use') = 'claim' AND fhirpath_text(InpatientEncounter.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(Claims.resource, 'item.encounter.reference'), '/'), -1)), 'item') ELSE NULL END, 'diagnosisSequence'), '["VARCHAR"]'), fhirpath_text(_lt_ClaimsDiag, 'sequence')) AND in_valueset(_lt_ClaimsDiag, 'onAdmission', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1147.197') AND in_valueset(_lt_ClaimsDiag, 'diagnosis', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1200.147'))
),
