"Risk Variable Encounter with Suicide Attempt" AS (
SELECT * FROM "Qualifying Encounter" AS InpatientEncounter WHERE EXISTS (SELECT 1 FROM (SELECT unnest((SELECT list(CASE WHEN (SELECT COUNT(*) FROM ((SELECT patient_id, resource FROM "Condition (qicore-condition-encounter-diagnosis)" AS ConditionED) UNION (SELECT patient_id, resource FROM "Condition (qicore-condition-problems-health-concerns)" AS ConditionPHC)) AS Cond WHERE fhirpath_text(Cond.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EncDiag, 'reference'), '/'), -1) AND Cond.patient_id = InpatientEncounter.patient_id) = 1 THEN (SELECT resource FROM ((SELECT patient_id, resource FROM "Condition (qicore-condition-encounter-diagnosis)" AS ConditionED) UNION (SELECT patient_id, resource FROM "Condition (qicore-condition-problems-health-concerns)" AS ConditionPHC)) AS Cond WHERE fhirpath_text(Cond.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EncDiag, 'reference'), '/'), -1) AND Cond.patient_id = InpatientEncounter.patient_id LIMIT 1) ELSE NULL END) FROM (SELECT unnest(from_json(fhirpath(InpatientEncounter.resource, 'reasonReference'), '["VARCHAR"]')) AS _lt_EncDiag) AS _lt_unnest)) AS _ivr) AS _ivt WHERE in_valueset(_ivr, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1248.130'))
),
